#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Function to calculate the determinant of a matrix
int calculateDeterminant(char ***matrix, int d) {
    if (d == 1) {
        // Base case: 1x1 matrix
        return atoi(matrix[0][0]);
    }

    int det = 0;
    for (int i = 0; i < d; i++) {
        // Create a sub-matrix by removing the first row and the i-th column
        char ***subMatrix = (char ***)malloc((d - 1) * sizeof(char **));
        for (int j = 0; j < d - 1; j++) {
            subMatrix[j] = (char **)malloc(d * sizeof(char *));
            for (int k = 0; k < d; k++) {
                if (k < i) {
                    subMatrix[j][k] = matrix[j + 1][k];
                } else {
                    subMatrix[j][k] = matrix[j + 1][k + 1];
                }
            }
        }

        // Recursively calculate the determinant of the sub-matrix
        int subDet = calculateDeterminant(subMatrix, d - 1);

        // Update the determinant using the cofactor expansion formula
        det += (i % 2 == 0 ? 1 : -1) * atoi(matrix[0][i]) * subDet;

        // Free the sub-matrix memory
        for (int j = 0; j < d - 1; j++) {
            free(subMatrix[j]);
        }
        free(subMatrix);
    }

    return det;
}

int main() {
    int T;
    scanf("%d", &T);

    for (int t = 0; t < T; t++) {
        int d;
        scanf("%d", &d);

        char ***matrix = (char ***)malloc(d * sizeof(char **));
        for (int i = 0; i < d; i++) {
            matrix[i] = (char **)malloc(d * sizeof(char *));
            for (int j = 0; j < d; j++) {
                matrix[i][j] = (char *)malloc(101 * sizeof(char));
                scanf("%s", matrix[i][j]);
            }
        }

        int det = calculateDeterminant(matrix, d);

        if (det % 2 == 0) {
            printf("All Even\n");
        } else {
            printf("Some Odd\n");
        }

        // Free the matrix memory
        for (int i = 0; i < d; i++) {
            for (int j = 0; j < d; j++) {
                free(matrix[i][j]);
            }
            free(matrix[i]);
        }
        free(matrix);
    }

    return 0;
}

