import java.util.Scanner;
public class Main {
    // Function to calculate the determinant of a matrix
    public static int calculateDeterminant(String[][] matrix, int d) {
        if (d == 1) {
            // Base case: 1x1 matrix
            return Integer.parseInt(matrix[0][0]);
        }

        int det = 0;
        for (int i = 0; i < d; i++) {
            // Create a sub-matrix by removing the first row and the i-th column
            String[][] subMatrix = new String[d - 1][d - 1];
            for (int j = 0; j < d - 1; j++) {
                for (int k = 0; k < d - 1; k++) {
                    if (k < i) {
                        subMatrix[j][k] = matrix[j + 1][k];
                    } else {
                        subMatrix[j][k] = matrix[j + 1][k + 1];
                    }
                }
            }

            // Recursively calculate the determinant of the sub-matrix
            int subDet = calculateDeterminant(subMatrix, d - 1);

            // Update the determinant using the cofactor expansion formula
            det += (i % 2 == 0 ? 1 : -1) * Integer.parseInt(matrix[0][i]) * subDet;
        }

        return det;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        scanner.nextLine();

        for (int t = 0; t < T; t++) {
            int d = scanner.nextInt();
            scanner.nextLine();

            String[][] matrix = new String[d][d];
            for (int i = 0; i < d; i++) {
                String[] row = scanner.nextLine().split(" ");
                for (int j = 0; j < d; j++) {
                    matrix[i][j] = row[j];
                }
            }

            int det = calculateDeterminant(matrix, d);

            if (det % 2 == 0) {
                System.out.println("All Even");
            } else {
                System.out.println("Some Odd");
            }
        }
    }
}

